<script>
document.addEventListener('DOMContentLoaded', function() {
    // ১. লাইভ ক্যাটাগরি ফিল্টার
    const tabBtns = document.querySelectorAll('.tab-btn');
    const menuCards = document.querySelectorAll('.menu-item-card');

    tabBtns.forEach(btn => {
        btn.addEventListener('click', () => {
            // Active class toggle
            tabBtns.forEach(b => b.classList.remove('active'));
            btn.classList.add('active');

            const filter = btn.getAttribute('data-filter');

            menuCards.forEach(card => {
                if (filter === 'all' || card.getAttribute('data-category') === filter) {
                    card.style.display = 'flex';
                    // Scroll reveal animation trigger (optional)
                    card.classList.add('active'); 
                } else {
                    card.style.display = 'none';
                }
            });
        });
    });

    // ২. লাইভ সার্চ ফিল্টার
    const searchInput = document.getElementById('menuSearchInput');
    searchInput.addEventListener('input', function() {
        const searchTerm = this.value.toLowerCase();

        menuCards.forEach(card => {
            const title = card.getAttribute('data-title');
            if (title.includes(searchTerm)) {
                card.style.display = 'flex';
            } else {
                card.style.display = 'none';
            }
        });

        // Reset tabs visually when searching
        if(searchTerm.length > 0) {
            tabBtns.forEach(b => b.classList.remove('active'));
        }
    });

    // ৩. কার্ট ড্রয়ার টগল লজিক (Basic UI Toggle)
    const floatingCartBtn = document.getElementById('floatingCartBtn');
    const cartDrawer = document.getElementById('cartDrawer');
    const cartOverlay = document.getElementById('cartOverlay');
    const closeCartBtn = document.getElementById('closeCartBtn');
    const continueShoppingBtn = document.getElementById('continueShoppingBtn');

    function openCart() {
        cartDrawer.classList.add('active');
        cartOverlay.classList.add('active');
        document.body.style.overflow = 'hidden'; // Prevent background scrolling
    }

    function closeCart() {
        cartDrawer.classList.remove('active');
        cartOverlay.classList.remove('active');
        document.body.style.overflow = '';
    }

    floatingCartBtn.addEventListener('click', openCart);
    closeCartBtn.addEventListener('click', closeCart);
    cartOverlay.addEventListener('click', closeCart);
    if(continueShoppingBtn) continueShoppingBtn.addEventListener('click', closeCart);

    // ৪. "কার্টে যোগ করুন" বাটন ইন্টারঅ্যাকশন (Placeholder for full cart logic)
    const addToCartBtns = document.querySelectorAll('.btn-add-to-cart');
    const cartBadge = document.getElementById('cartBadge');
    let cartCount = 0;

    addToCartBtns.forEach(btn => {
        btn.addEventListener('click', function() {
            // Animation feedback
            const originalText = this.innerHTML;
            this.innerHTML = '<i class="fas fa-check"></i> যোগ হয়েছে';
            this.style.background = '#10b981';
            this.style.color = '#fff';
            this.style.borderColor = '#10b981';

            cartCount++;
            cartBadge.textContent = cartCount;

            // Show cart summary if it was hidden
            document.getElementById('cartSummary').style.display = 'block';
            document.querySelector('.empty-cart-message').style.display = 'none';

            setTimeout(() => {
                this.innerHTML = originalText;
                this.style.background = '';
                this.style.color = '';
                this.style.borderColor = '';
            }, 1500);

            // Optional: Auto open cart on add
            // openCart();
        });
    });
});
</script>

